from argparse import ArgumentParser
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(args):
    admin = KafkaAdminClient(bootstrap_servers='localhost:9092')
    
    topic = NewTopic(name=args.topic_name, num_partitions=args.num_partitions, replication_factor=args.replication_factor)
    try:
        admin.create_topics([topic])
        print("Topic created successfully.")
    except Exception as e:
        print(f"Failed to create topic due to {str(e)}")
    
if __name__ == "__main__":
    parser = ArgumentParser()
    parser.add_argument("--topic_name", required=True, help="Name of the Kafka Topic.")
    parser.add_argument("--num_partitions", type=int, default=1, help="Number of partitions for the topic.")
    parser.add_argument("--replication_factor", type=int, default=1, help="Replication factor for the topic.")
    
    args = parser.parse_args()
    create_topic(args)